import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { getRFQDetail, submitBid } from "../api/axios";
import BidTable from "../components/BidTable";
import ActivityLog from "../components/ActivityLog";

const statusBadge = (status) => {
  const badges = {
    active: { bg: "bg-gradient-to-r from-emerald-50 to-teal-50", border: "border-emerald-200", text: "text-emerald-700", icon: "🟢" },
    force_closed: { bg: "bg-gradient-to-r from-red-50 to-pink-50", border: "border-red-200", text: "text-red-700", icon: "🔴" },
    closed: { bg: "bg-gradient-to-r from-gray-50 to-slate-50", border: "border-gray-200", text: "text-gray-700", icon: "⭕" },
  };
  const badge = badges[status] || badges.closed;
  const label = status === "active" ? "Active" : status === "force_closed" ? "Force Closed" : "Closed";
  return (
    <span className={`inline-flex items-center space-x-1 px-4 py-2 rounded-full text-sm font-semibold ${badge.bg} ${badge.border} ${badge.text} border`}>
      <span className="text-lg">{badge.icon}</span>
      <span>{label}</span>
    </span>
  );
};

const formatDateTime = (dt) => {
  if (!dt) return "";
  const d = new Date(dt);
  return d.toLocaleString("en-GB", {
    day: "2-digit",
    month: "short",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  });
};

const CountdownTimer = ({ endTime }) => {
  const [timeLeft, setTimeLeft] = useState("");
  useEffect(() => {
    const interval = setInterval(() => {
      const now = new Date();
      const end = new Date(endTime);
      const diff = Math.max(0, end - now);
      const hours = String(Math.floor(diff / 3600000)).padStart(2, "0");
      const minutes = String(Math.floor((diff % 3600000) / 60000)).padStart(2, "0");
      const seconds = String(Math.floor((diff % 60000) / 1000)).padStart(2, "0");
      setTimeLeft(`${hours}:${minutes}:${seconds}`);
    }, 1000);
    return () => clearInterval(interval);
  }, [endTime]);
  return (
    <span className="font-mono text-2xl font-bold tabular-nums bg-gradient-to-r from-blue-600 to-cyan-600 bg-clip-text text-transparent">
      {timeLeft}
    </span>
  );
};

const AuctionDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [rfq, setRfq] = useState(null);
  const [loading, setLoading] = useState(true);
  const [bidForm, setBidForm] = useState({
    carrier_name: "",
    freight_charges: "",
    origin_charges: "",
    destination_charges: "",
    transit_time: "",
    quote_validity: "",
  });
  const [bidError, setBidError] = useState("");
  const [bidSuccess, setBidSuccess] = useState("");
  const [submitting, setSubmitting] = useState(false);

  const fetchDetail = async () => {
    setLoading(true);
    try {
      const data = await getRFQDetail(id);
      setRfq(data);
    } catch (e) {
      setRfq(null);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchDetail();
    const interval = setInterval(fetchDetail, 15000);
    return () => clearInterval(interval);
  }, [id]);

  const handleBidChange = (e) => {
    const { name, value } = e.target;
    setBidForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleBidSubmit = async (e) => {
    e.preventDefault();
    setBidError("");
    setBidSuccess("");
    setSubmitting(true);
    try {
      const payload = {
        ...bidForm,
        freight_charges: Number(bidForm.freight_charges),
        origin_charges: Number(bidForm.origin_charges),
        destination_charges: Number(bidForm.destination_charges),
        transit_time: Number(bidForm.transit_time),
        quote_validity: bidForm.quote_validity,
      };
      await submitBid(id, payload);
      setBidSuccess("Bid submitted successfully!");
      setBidForm({
        carrier_name: "",
        freight_charges: "",
        origin_charges: "",
        destination_charges: "",
        transit_time: "",
        quote_validity: "",
      });
      fetchDetail();
    } catch (error) {
      setBidError(error.response?.data?.detail || "Failed to submit bid.");
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <svg className="animate-spin h-12 w-12 text-blue-600 mx-auto mb-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8z"></path></svg>
          <p className="text-gray-500 font-medium">Loading auction details...</p>
        </div>
      </div>
    );
  }

  if (!rfq) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <svg className="h-16 w-16 text-red-500 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 8v4m0 4v.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          <h2 className="text-2xl font-bold text-gray-900 mb-2">RFQ Not Found</h2>
          <button onClick={() => navigate("/")} className="text-blue-600 hover:text-blue-700 font-medium">← Back to Auctions</button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-6xl mx-auto">
        {/* Back Button */}
        <button
          onClick={() => navigate("/")}
          className="mb-6 flex items-center space-x-2 text-blue-600 hover:text-blue-700 font-medium transition"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
          <span>Back to Auctions</span>
        </button>

        {/* Header Section */}
        <div className="bg-white rounded-xl shadow-xl overflow-hidden mb-8">
          <div className="h-2 bg-gradient-to-r from-blue-500 via-cyan-400 to-blue-500"></div>
          <div className="p-8">
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between mb-6">
              <div>
                <h1 className="text-4xl font-bold text-gray-900 mb-2">{rfq.name}</h1>
                <p className="text-gray-600 font-mono">Reference: {rfq.reference_id}</p>
              </div>
              {statusBadge(rfq.status)}
            </div>

            {/* Key Info Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 mt-8 pt-8 border-t border-gray-100">
              {/* Lowest Bid */}
              <div className="text-center">
                <p className="text-sm font-semibold text-gray-600 mb-2">🏆 Lowest Bid</p>
                {rfq.bids && rfq.bids.length > 0 ? (
                  <p className="text-3xl font-bold text-green-600">£{rfq.bids[0]?.total_charges?.toFixed(2) || "N/A"}</p>
                ) : (
                  <p className="text-2xl font-bold text-gray-400">No bids yet</p>
                )}
              </div>

              {/* Bid Count */}
              <div className="text-center">
                <p className="text-sm font-semibold text-gray-600 mb-2">📈 Total Bids</p>
                <p className="text-3xl font-bold text-blue-600">{rfq.bids?.length || 0}</p>
              </div>

              {/* Time Left */}
              <div className="text-center">
                <p className="text-sm font-semibold text-gray-600 mb-2">⏱️ Time Remaining</p>
                <CountdownTimer endTime={rfq.bid_close_time} />
              </div>
            </div>
          </div>
        </div>

        {/* Config & Timeline Card */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
          {/* Configuration */}
          <div className="bg-white rounded-xl shadow-lg p-6 border-l-4 border-purple-500">
            <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center space-x-2">
              <svg className="w-5 h-5 text-purple-600" fill="currentColor" viewBox="0 0 20 20"><path d="M11.3 1.046A1 1 0 0112 2v5h4a1 1 0 01.82 1.573l-7 10A1 1 0 018 17v-5H4a1 1 0 01-.82-1.573l7-10a1 1 0 011.12-.381z" /></svg>
              <span>Auction Configuration</span>
            </h3>
            <div className="space-y-3">
              <div className="flex justify-between items-center pb-2 border-b border-gray-100">
                <span className="text-gray-600 font-medium">Trigger Window</span>
                <span className="font-mono font-bold text-gray-900">{rfq.trigger_window_minutes} minutes</span>
              </div>
              <div className="flex justify-between items-center pb-2 border-b border-gray-100">
                <span className="text-gray-600 font-medium">Extension Duration</span>
                <span className="font-mono font-bold text-gray-900">{rfq.extension_duration_minutes} minutes</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-gray-600 font-medium">Trigger Type</span>
                <span className="font-mono font-bold text-blue-600 bg-blue-50 px-2 py-1 rounded">{rfq.extension_trigger_type}</span>
              </div>
            </div>
          </div>

          {/* Timeline */}
          <div className="bg-white rounded-xl shadow-lg p-6 border-l-4 border-blue-500">
            <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center space-x-2">
              <svg className="w-5 h-5 text-blue-600" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M6 2a1 1 0 00-1 1v1H4a2 2 0 00-2 2v2a2 2 0 002 2h12a2 2 0 002-2V6a2 2 0 00-2-2h-1V3a1 1 0 10-2 0v1H7V3a1 1 0 00-1-1zm0 5a1 1 0 000 2h8a1 1 0 100-2H6z" clipRule="evenodd" /></svg>
              <span>Timeline</span>
            </h3>
            <div className="space-y-4">
              <div>
                <p className="text-xs font-semibold text-gray-500 mb-1">Bid Start</p>
                <p className="font-mono text-gray-900">{formatDateTime(rfq.bid_start_time)}</p>
              </div>
              <div>
                <p className="text-xs font-semibold text-gray-500 mb-1">Bid Close</p>
                <p className="font-mono text-gray-900">{formatDateTime(rfq.bid_close_time)}</p>
              </div>
              <div>
                <p className="text-xs font-semibold text-gray-500 mb-1">Force Close</p>
                <p className="font-mono text-red-600 font-bold">{formatDateTime(rfq.forced_close_time)}</p>
              </div>
              <div>
                <p className="text-xs font-semibold text-gray-500 mb-1">Pickup Date</p>
                <p className="font-mono text-gray-900">{rfq.pickup_date}</p>
              </div>
            </div>
          </div>
        </div>

        {/* Bids Section */}
        <div className="bg-white rounded-xl shadow-xl overflow-hidden mb-8">
          <div className="h-1 bg-gradient-to-r from-green-500 to-emerald-500"></div>
          <div className="p-8">
            <h2 className="text-2xl font-bold text-gray-900 mb-6 flex items-center space-x-2">
              <svg className="w-6 h-6 text-green-600" fill="currentColor" viewBox="0 0 20 20"><path d="M8 16.5a1.5 1.5 0 11-3 0 1.5 1.5 0 013 0zM15 16.5a1.5 1.5 0 11-3 0 1.5 1.5 0 013 0z" /><path d="M3 4a1 1 0 00-1 1v10a1 1 0 001 1h1.05a2.5 2.5 0 014.9 0H10a1 1 0 001-1V5a1 1 0 00-1-1H3zM14 7a1 1 0 00-1 1v6.05A2.5 2.5 0 0115.95 16H17a1 1 0 001-1v-5a1 1 0 00-.293-.707l-2-2A1 1 0 0015 7h-1z" /></svg>
              <span>Bid Leaderboard</span>
            </h2>
            <BidTable bids={rfq.bids} />
          </div>
        </div>

        {/* Activity Log Section */}
        <div className="bg-white rounded-xl shadow-xl overflow-hidden mb-8">
          <div className="h-1 bg-gradient-to-r from-orange-500 to-red-500"></div>
          <div className="p-8">
            <h2 className="text-2xl font-bold text-gray-900 mb-6 flex items-center space-x-2">
              <svg className="w-6 h-6 text-orange-600" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M5 2a1 1 0 011 1v1h1V3a1 1 0 011-1h1V1a1 1 0 011 1v1h1V3a1 1 0 011-1h1V1a1 1 0 011 1v1h1V3a1 1 0 01-1-1V2h1a2 2 0 012 2v2h1a1 1 0 110 2h-1v1h1a1 1 0 110 2h-1v1h1a1 1 0 110 2h-1v2a2 2 0 01-2 2h-2v1a1 1 0 11-2 0v-1h-1v1a1 1 0 11-2 0v-1H7v1a1 1 0 01-2 0v-1H4a2 2 0 01-2-2v-2H1a1 1 0 110-2h1v-1H1a1 1 0 110-2h1V9H1a1 1 0 110-2h1V6H1a1 1 0 110-2h1V4a2 2 0 012-2h2V1a1 1 0 011-1zm0 4v10h10V6H5z" clipRule="evenodd" /></svg>
              <span>Activity Log</span>
            </h2>
            <ActivityLog events={rfq.auction_events} />
          </div>
        </div>

        {/* Submit Bid Section */}
        {rfq.status === "active" && (
          <div className="bg-white rounded-xl shadow-xl overflow-hidden">
            <div className="h-1 bg-gradient-to-r from-cyan-500 to-blue-500"></div>
            <div className="p-8">
              <h2 className="text-2xl font-bold text-gray-900 mb-6 flex items-center space-x-2">
                <svg className="w-6 h-6 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                <span>Submit New Bid</span>
              </h2>

              <form onSubmit={handleBidSubmit} className="space-y-6">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-2">Carrier Name *</label>
                    <input
                      type="text"
                      name="carrier_name"
                      value={bidForm.carrier_name}
                      onChange={handleBidChange}
                      className="w-full px-4 py-2.5 border-2 border-gray-300 rounded-lg focus:outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition"
                      placeholder="Enter carrier name"
                      required
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-2">Transit Time (days) *</label>
                    <input
                      type="number"
                      name="transit_time"
                      value={bidForm.transit_time}
                      onChange={handleBidChange}
                      className="w-full px-4 py-2.5 border-2 border-gray-300 rounded-lg focus:outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition"
                      required
                      min="1"
                      placeholder="Days"
                    />
                  </div>
                </div>

                <div>
                  <h3 className="font-semibold text-gray-900 mb-4">Charges Breakdown</h3>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                    <div>
                      <label className="block text-sm font-semibold text-gray-700 mb-2">Freight Charges (£) *</label>
                      <input
                        type="number"
                        name="freight_charges"
                        value={bidForm.freight_charges}
                        onChange={handleBidChange}
                        className="w-full px-4 py-2.5 border-2 border-gray-300 rounded-lg focus:outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition"
                        required
                        min="0"
                        step="0.01"
                        placeholder="0.00"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-semibold text-gray-700 mb-2">Origin Charges (£) *</label>
                      <input
                        type="number"
                        name="origin_charges"
                        value={bidForm.origin_charges}
                        onChange={handleBidChange}
                        className="w-full px-4 py-2.5 border-2 border-gray-300 rounded-lg focus:outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition"
                        required
                        min="0"
                        step="0.01"
                        placeholder="0.00"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-semibold text-gray-700 mb-2">Destination Charges (£) *</label>
                      <input
                        type="number"
                        name="destination_charges"
                        value={bidForm.destination_charges}
                        onChange={handleBidChange}
                        className="w-full px-4 py-2.5 border-2 border-gray-300 rounded-lg focus:outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition"
                        required
                        min="0"
                        step="0.01"
                        placeholder="0.00"
                      />
                    </div>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Quote Validity *</label>
                  <input
                    type="date"
                    name="quote_validity"
                    value={bidForm.quote_validity}
                    onChange={handleBidChange}
                    className="w-full px-4 py-2.5 border-2 border-gray-300 rounded-lg focus:outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition"
                    required
                  />
                </div>

                {bidError && (
                  <div className="bg-red-50 border-l-4 border-red-500 p-4 rounded">
                    <p className="text-red-700 font-medium">⚠ {bidError}</p>
                  </div>
                )}

                {bidSuccess && (
                  <div className="bg-green-50 border-l-4 border-green-500 p-4 rounded">
                    <p className="text-green-700 font-medium">✓ {bidSuccess}</p>
                  </div>
                )}

                <button
                  type="submit"
                  className="w-full bg-gradient-to-r from-blue-600 to-cyan-600 text-white font-semibold py-3 rounded-lg hover:from-blue-700 hover:to-cyan-700 transition shadow-lg hover:shadow-xl disabled:opacity-50"
                  disabled={submitting}
                >
                  {submitting ? (
                    <span className="flex items-center justify-center space-x-2">
                      <svg className="animate-spin h-5 w-5" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8z"></path></svg>
                      <span>Submitting...</span>
                    </span>
                  ) : (
                    <span className="flex items-center justify-center space-x-2">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                      <span>Submit Bid</span>
                    </span>
                  )}
                </button>
              </form>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AuctionDetail;
